26	/*
27	 * In order to ensure that C++ exceptions are converted to Python
28	 * ones before crossing over to the C machinery, we must catch them.
29	 * This template can be used to wrap a C++ written ufunc to do this via:
30	 *      wrap_legacy_cpp_ufunc<cpp_ufunc>
31	 */
32	template<PyUFuncGenericFunction cpp_ufunc>
33	static void
34	wrap_legacy_cpp_ufunc(char **args, npy_intp const *dimensions,
35	                      npy_intp const *steps, void *func)
36	{
37	    NPY_ALLOW_C_API_DEF
38	    try {
39	        cpp_ufunc(args, dimensions, steps, func);
40	    }
41	    catch (std::bad_alloc& e) {
42	        NPY_ALLOW_C_API;
43	        PyErr_NoMemory();
44	        NPY_DISABLE_C_API;
45	    }
46	    catch (const std::exception& e) {
47	        NPY_ALLOW_C_API;
48	        PyErr_SetString(PyExc_RuntimeError, e.what());
49	        NPY_DISABLE_C_API;
50	    }
51	}
