53	/*
54	 * Transfer to and from a contiguous buffer.
55	 * copy_input: copy min(nin, n) elements from input to buffer and zero rest.
56	 * copy_output: copy n elements from buffer to output.
57	 */
58	template <typename T>
59	static inline void
60	copy_input(char *in, npy_intp step_in, size_t nin,
61	           T buff[], size_t n)
62	{
63	    size_t ncopy = nin <= n ? nin : n;
64	    char *ip = in;
65	    size_t i;
66	    for (i = 0; i < ncopy; i++, ip += step_in) {
67	      buff[i] = *(T *)ip;
68	    }
69	    for (; i < n; i++) {
70	      buff[i] = 0;
71	    }
72	}
73	
74	template <typename T>
75	static inline void
76	copy_output(T buff[], char *out, npy_intp step_out, size_t n)
77	{
78	    char *op = out;
79	    for (size_t i = 0; i < n; i++, op += step_out) {
80	        *(T *)op = buff[i];
81	    }
82	}
