84	/*
85	 * Gufunc loops calling the pocketfft code.
86	 */
87	template <typename T>
88	static void
89	fft_loop(char **args, npy_intp const *dimensions, npy_intp const *steps,
90	         void *func)
91	{
92	    char *ip = args[0], *fp = args[1], *op = args[2];
93	    size_t n_outer = (size_t)dimensions[0];
94	    npy_intp si = steps[0], sf = steps[1], so = steps[2];
95	    size_t nin = (size_t)dimensions[1], nout = (size_t)dimensions[2];
96	    npy_intp step_in = steps[3], step_out = steps[4];
97	    bool direction = *((bool *)func); /* pocketfft::FORWARD or BACKWARD */
98	
99	    assert (nout > 0);
100	
101	#ifndef POCKETFFT_NO_VECTORS
102	    /*
103	     * For the common case of nin >= nout, fixed factor, and suitably sized
104	     * outer loop, we call pocketfft directly to benefit from its vectorization.
105	     * (For nin>nout, this just removes the extra input points, as required;
106	     * the vlen constraint avoids compiling extra code for longdouble, which
107	     * cannot be vectorized so does not benefit.)
108	     */
109	    constexpr auto vlen = pocketfft::detail::VLEN<T>::val;
110	    if (vlen > 1 && n_outer >= vlen && nin >= nout && sf == 0) {
111	        std::vector<size_t> shape = { n_outer, nout };
112	        std::vector<ptrdiff_t> strides_in = { si, step_in };
113	        std::vector<ptrdiff_t> strides_out = { so, step_out};
114	        std::vector<size_t> axes = { 1 };
115	        pocketfft::c2c(shape, strides_in, strides_out, axes, direction,
116	                       (std::complex<T> *)ip, (std::complex<T> *)op, *(T *)fp);
117	        return;
118	    }
119	#endif
120	    /*
121	     * Otherwise, use a non-vectorized loop in which we try to minimize copies.
122	     * We do still need a buffer if the output is not contiguous.
123	     */
124	    auto plan = pocketfft::detail::get_plan<pocketfft::detail::pocketfft_c<T>>(nout);
125	    auto buffered = (step_out != sizeof(std::complex<T>));
126	    pocketfft::detail::arr<std::complex<T>> buff(buffered ? nout : 0);
127	    for (size_t i = 0; i < n_outer; i++, ip += si, fp += sf, op += so) {
128	        std::complex<T> *op_or_buff = buffered ? buff.data() : (std::complex<T> *)op;
129	        if (ip != (char*)op_or_buff) {
130	            copy_input(ip, step_in, nin, op_or_buff, nout);
131	        }
132	        plan->exec((pocketfft::detail::cmplx<T> *)op_or_buff, *(T *)fp, direction);
133	        if (buffered) {
134	            copy_output(op_or_buff, op, step_out, nout);
135	        }
136	    }
137	    return;
138	}
