140	template <typename T>
141	static void
142	rfft_impl(char **args, npy_intp const *dimensions, npy_intp const *steps,
143	          void *func, size_t npts)
144	{
145	    char *ip = args[0], *fp = args[1], *op = args[2];
146	    size_t n_outer = (size_t)dimensions[0];
147	    npy_intp si = steps[0], sf = steps[1], so = steps[2];
148	    size_t nin = (size_t)dimensions[1], nout = (size_t)dimensions[2];
149	    npy_intp step_in = steps[3], step_out = steps[4];
150	
151	    assert (nout > 0 && nout == npts / 2 + 1);
152	
153	#ifndef POCKETFFT_NO_VECTORS
154	    /*
155	     * Call pocketfft directly if vectorization is possible.
156	     */
157	    constexpr auto vlen = pocketfft::detail::VLEN<T>::val;
158	    if (vlen > 1 && n_outer >= vlen && nin >= npts && sf == 0) {
159	        std::vector<size_t> shape_in = { n_outer, npts };
160	        std::vector<ptrdiff_t> strides_in = { si, step_in };
161	        std::vector<ptrdiff_t> strides_out = { so, step_out};
162	        std::vector<size_t> axes = { 1 };
163	        pocketfft::r2c(shape_in, strides_in, strides_out, axes, pocketfft::FORWARD,
164	                       (T *)ip, (std::complex<T> *)op, *(T *)fp);
165	        return;
166	    }
167	#endif
168	    /*
169	     * Otherwise, use a non-vectorized loop in which we try to minimize copies.
170	     * We do still need a buffer if the output is not contiguous.
171	     */
172	    auto plan = pocketfft::detail::get_plan<pocketfft::detail::pocketfft_r<T>>(npts);
173	    auto buffered = (step_out != sizeof(std::complex<T>));
174	    pocketfft::detail::arr<std::complex<T>> buff(buffered ? nout : 0);
175	    auto nin_used = nin <= npts ? nin : npts;
176	    for (size_t i = 0; i < n_outer; i++, ip += si, fp += sf, op += so) {
177	        std::complex<T> *op_or_buff = buffered ? buff.data() : (std::complex<T> *)op;
178	        /*
179	         * The internal pocketfft routines work in-place and for real
180	         * transforms the frequency data thus needs to be compressed, using
181	         * that there will be no imaginary component for the zero-frequency
182	         * item (which is the sum of all inputs and thus has to be real), nor
183	         * one for the Nyquist frequency for even number of points.
184	         * Pocketfft uses FFTpack order, R0,R1,I1,...Rn-1,In-1,Rn[,In] (last
185	         * for npts odd only). To make unpacking easy, we place the real data
186	         * offset by one in the buffer, so that we just have to move R0 and
187	         * create I0=0. Note that copy_input will zero the In component for
188	         * even number of points.
189	         */
190	        copy_input(ip, step_in, nin_used, &((T *)op_or_buff)[1], nout*2 - 1);
191	        plan->exec(&((T *)op_or_buff)[1], *(T *)fp, pocketfft::FORWARD);
192	        op_or_buff[0] = op_or_buff[0].imag();  // I0->R0, I0=0
193	        if (buffered) {
194	            copy_output(op_or_buff, op, step_out, nout);
195	        }
196	    }
197	    return;
198	}
