200	/*
201	 * For the forward real, we cannot know what the requested number of points is
202	 * just based on the number of points in the complex output array (e.g., 10
203	 * and 11 real input points both lead to 6 complex output points), so we
204	 * define versions for both even and odd number of points.
205	 */
206	template <typename T>
207	static void
208	rfft_n_even_loop(char **args, npy_intp const *dimensions, npy_intp const *steps, void *func)
209	{
210	    size_t nout = (size_t)dimensions[2];
211	    assert (nout > 0);
212	    size_t npts = 2 * nout - 2;
213	    rfft_impl<T>(args, dimensions, steps, func, npts);
214	}
215	
216	template <typename T>
217	static void
218	rfft_n_odd_loop(char **args, npy_intp const *dimensions, npy_intp const *steps, void *func)
219	{
220	    size_t nout = (size_t)dimensions[2];
221	    assert (nout > 0);
222	    size_t npts = 2 * nout - 1;
223	    rfft_impl<T>(args, dimensions, steps, func, npts);
224	}
