226	template <typename T>
227	static void
228	irfft_loop(char **args, npy_intp const *dimensions, npy_intp const *steps, void *func)
229	{
230	    char *ip = args[0], *fp = args[1], *op = args[2];
231	    size_t n_outer = (size_t)dimensions[0];
232	    ptrdiff_t si = steps[0], sf = steps[1], so = steps[2];
233	    size_t nin = (size_t)dimensions[1], nout = (size_t)dimensions[2];
234	    ptrdiff_t step_in = steps[3], step_out = steps[4];
235	
236	    assert(nout > 0);
237	
238	#ifndef POCKETFFT_NO_VECTORS
239	    /*
240	     * Call pocketfft directly if vectorization is possible.
241	     */
242	    size_t npts_in = nout / 2 + 1;
243	    constexpr auto vlen = pocketfft::detail::VLEN<T>::val;
244	    if (vlen > 1 && n_outer >= vlen && nin >= npts_in && sf == 0) {
245	        std::vector<size_t> axes = { 1 };
246	        std::vector<size_t> shape_out = { n_outer, nout };
247	        std::vector<ptrdiff_t> strides_in = { si, step_in };
248	        std::vector<ptrdiff_t> strides_out = { so, step_out};
249	        pocketfft::c2r(shape_out, strides_in, strides_out, axes, pocketfft::BACKWARD,
250	                       (std::complex<T> *)ip, (T *)op, *(T *)fp);
251	        return;
252	    }
253	#endif
254	    /*
255	     * Otherwise, use a non-vectorized loop in which we try to minimize copies.
256	     * We do still need a buffer if the output is not contiguous.
257	     */
258	    auto plan = pocketfft::detail::get_plan<pocketfft::detail::pocketfft_r<T>>(nout);
259	    auto buffered = (step_out != sizeof(T));
260	    pocketfft::detail::arr<T> buff(buffered ? nout : 0);
261	    for (size_t i = 0; i < n_outer; i++, ip += si, fp += sf, op += so) {
262	        T *op_or_buff = buffered ? buff.data() : (T *)op;
263	        /*
264	         * Pocket_fft works in-place and for inverse real transforms the
265	         * frequency data thus needs to be compressed, removing the imaginary
266	         * component of the zero-frequency item (which is the sum of all
267	         * inputs and thus has to be real), as well as the imaginary component
268	         * of the Nyquist frequency for even number of points. We thus copy
269	         * the data to the buffer in the following order (also used by
270	         * FFTpack): R0,R1,I1,...Rn-1,In-1,Rn[,In] (last for npts odd only).
271	         */
272	        op_or_buff[0] = ((T *)ip)[0];  /* copy R0 */
273	        if (nout > 1) {
274	            /*
275	             * Copy R1,I1... up to Rn-1,In-1 if possible, stopping earlier
276	             * if not all the input points are needed or if the input is short
277	             * (in the latter case, zeroing after).
278	             */
279	            copy_input(ip + step_in, step_in, nin - 1,
280	                       (std::complex<T> *)&op_or_buff[1], (nout - 1) / 2);
281	            /* For even nout, we still need to set Rn. */
282	            if (nout % 2 == 0) {
283	                op_or_buff[nout - 1] = (nout / 2 >= nin) ? (T)0 :
284	                    ((T *)(ip + (nout / 2) * step_in))[0];
285	            }
286	        }
287	        plan->exec(op_or_buff, *(T *)fp, pocketfft::BACKWARD);
288	        if (buffered) {
289	            copy_output(op_or_buff, op, step_out, nout);
290	        }
291	    }
292	    return;
293	}
