343	static int
344	add_gufuncs(PyObject *dictionary) {
345	    PyObject *f;
346	
347	    f = PyUFunc_FromFuncAndDataAndSignature(
348	        fft_functions, fft_data, fft_types, 3, 2, 1, PyUFunc_None,
349	        "fft", "complex forward FFT\n", 0, "(n),()->(m)");
350	    if (f == NULL) {
351	        return -1;
352	    }
353	    PyDict_SetItemString(dictionary, "fft", f);
354	    Py_DECREF(f);
355	    f = PyUFunc_FromFuncAndDataAndSignature(
356	        fft_functions, ifft_data, fft_types, 3, 2, 1, PyUFunc_None,
357	        "ifft", "complex backward FFT\n", 0, "(m),()->(n)");
358	    if (f == NULL) {
359	        return -1;
360	    }
361	    PyDict_SetItemString(dictionary, "ifft", f);
362	    Py_DECREF(f);
363	    f = PyUFunc_FromFuncAndDataAndSignature(
364	        rfft_n_even_functions, NULL, rfft_types, 3, 2, 1, PyUFunc_None,
365	        "rfft_n_even", "real forward FFT for even n\n", 0, "(n),()->(m)");
366	    if (f == NULL) {
367	        return -1;
368	    }
369	    PyDict_SetItemString(dictionary, "rfft_n_even", f);
370	    Py_DECREF(f);
371	    f = PyUFunc_FromFuncAndDataAndSignature(
372	        rfft_n_odd_functions, NULL, rfft_types, 3, 2, 1, PyUFunc_None,
373	        "rfft_n_odd", "real forward FFT for odd n\n", 0, "(n),()->(m)");
374	    if (f == NULL) {
375	        return -1;
376	    }
377	    PyDict_SetItemString(dictionary, "rfft_n_odd", f);
378	    Py_DECREF(f);
379	    f = PyUFunc_FromFuncAndDataAndSignature(
380	        irfft_functions, NULL, irfft_types, 3, 2, 1, PyUFunc_None,
381	        "irfft", "real backward FFT\n", 0, "(m),()->(n)");
382	    if (f == NULL) {
383	        return -1;
384	    }
385	    PyDict_SetItemString(dictionary, "irfft", f);
386	    Py_DECREF(f);
387	    return 0;
388	}
