390	static int module_loaded = 0;
391	
392	static int
393	_pocketfft_umath_exec(PyObject *m)
394	{
395	    // https://docs.python.org/3/howto/isolating-extensions.html#opt-out-limiting-to-one-module-object-per-process
396	    if (module_loaded) {
397	        PyErr_SetString(PyExc_ImportError,
398	                        "cannot load module more than once per process");
399	        return -1;
400	    }
401	    module_loaded = 1;
402	
403	    /* Import the array and ufunc objects */
404	    if (PyArray_ImportNumPyAPI() < 0) {
405	        return -1;
406	    }
407	    if (PyUFunc_ImportUFuncAPI() < 0) {
408	        return -1;
409	    }
410	
411	    PyObject *d = PyModule_GetDict(m);
412	    if (add_gufuncs(d) < 0) {
413	        Py_DECREF(d);
414	        return -1;
415	    }
416	
417	    return 0;
418	}
